449: // startResync periodically calls r.store.Resync() method.
450: // Note that this method is blocking and should be
451: // called in a separate goroutine.
452: func (r *Reflector) startResync(ctx context.Context, resyncerrc chan error) {
453: 	logger := klog.FromContext(ctx)
454: 	resyncCh, cleanup := r.resyncChan()
455: 	defer func() {
456: 		cleanup() // Call the last one written into cleanup
457: 	}()
458: 	for {
459: 		select {
460: 		case <-resyncCh:
461: 		case <-ctx.Done():
462: 			return
463: 		}
464: 		if r.ShouldResync == nil || r.ShouldResync() {
465: 			logger.V(4).Info("Forcing resync", "reflector", r.name)
466: 			if err := r.store.Resync(); err != nil {
467: 				resyncerrc <- err
468: 				return
469: 			}
470: 		}
471: 		cleanup()
472: 		resyncCh, cleanup = r.resyncChan()
473: 	}
474: }
